// Size selection function - synchronized across all sections
function selectSize(size) {
  console.log('Selected size:', size);
  
  // Update Buy Now button URLs
  updateBuyNowUrls(size);
  
  // Synchronize all Regular Size buttons
  if (size === 'regular') {
    // Update hero section size buttons
    var heroButtons = document.querySelectorAll('.mme-hero-tab-btn');
    heroButtons.forEach(function(btn) {
      if (btn.getAttribute('data-hero-tab') === 'regular') {
        btn.style.background = 'var(--mme-brand)';
        btn.style.color = '#fff';
      } else if (btn.getAttribute('data-hero-tab') === 'xl') {
        btn.style.background = 'transparent';
        btn.style.color = 'var(--mme-muted)';
      }
    });
    
    // Update use cases tabs
    switchTab('regular');
    
    // Update video tabs
    switchVideoTab('regular');
  } else if (size === 'xl') {
    // Update hero section size buttons
    var heroButtons = document.querySelectorAll('.mme-hero-tab-btn');
    heroButtons.forEach(function(btn) {
      if (btn.getAttribute('data-hero-tab') === 'xl') {
        btn.style.background = 'var(--mme-brand)';
        btn.style.color = '#fff';
      } else if (btn.getAttribute('data-hero-tab') === 'regular') {
        btn.style.background = 'transparent';
        btn.style.color = 'var(--mme-muted)';
      }
    });
    
    // Update use cases tabs
    switchTab('xl');
    
    // Update video tabs
    switchVideoTab('xl');
  }
}

// Function to update Buy Now button URLs
function updateBuyNowUrls(size) {
  var buyNowButtons = document.querySelectorAll('a[data-gtm-cta="shopify"]');
  var urls = {
    'regular': 'https://memotherearthbrand.com/products/quick-dry-diatomite-mat',
    'xl': 'https://memotherearthbrand.com/products/xlquick-dry-diatomaceous-earth-floor-stone-bath-and-dish-mat-bathroom-shower-mat-non-slip-super-absorbent-eco-friendly-sustainable'
  };
  
  buyNowButtons.forEach(function(btn) {
    if (urls[size]) {
      btn.href = urls[size];
    }
  });
}

// Tab switching function for Use Cases section - synchronized
function switchTab(tabName) {
  console.log('Switched to tab:', tabName);
  
  // Update Buy Now button URLs
  updateBuyNowUrls(tabName);
  
  // Update use cases tab button styles
  var tabButtons = document.querySelectorAll('.mme-tab-btn');
  tabButtons.forEach(function(btn) {
    if (btn.getAttribute('data-tab') === tabName) {
      btn.style.background = 'var(--mme-brand)';
      btn.style.color = '#fff';
    } else {
      btn.style.background = 'transparent';
      btn.style.color = 'var(--mme-muted)';
    }
  });
  
  // Update hero section size buttons
  var heroButtons = document.querySelectorAll('.mme-hero-tab-btn');
  heroButtons.forEach(function(btn) {
    if (btn.getAttribute('data-hero-tab') === tabName) {
      btn.style.background = 'var(--mme-brand)';
      btn.style.color = '#fff';
    } else {
      btn.style.background = 'transparent';
      btn.style.color = 'var(--mme-muted)';
    }
  });
  
  // Update video tabs (without calling switchTab to avoid infinite loop)
  var videoTabButtons = document.querySelectorAll('.mme-video-tab-btn');
  videoTabButtons.forEach(function(btn) {
    if (btn.getAttribute('data-video-tab') === tabName) {
      btn.style.background = 'var(--mme-brand)';
      btn.style.color = '#fff';
    } else {
      btn.style.background = 'transparent';
      btn.style.color = 'var(--mme-muted)';
    }
  });
  
  // Switch video based on tab
  var videoIframe = document.getElementById('promise-video');
  if (videoIframe) {
    var videoUrls = {
      'regular': 'https://www.youtube.com/embed/ki_PJ-atUD8',
      'xl': 'https://www.youtube.com/embed/vh7pj2sNDHg'
    };
    
    if (videoUrls[tabName]) {
      videoIframe.src = videoUrls[tabName];
    }
  }
  
  // Switch tab content
  var regularContent = document.getElementById('regular-content');
  var xlContent = document.getElementById('xl-content');
  
  if (tabName === 'regular') {
    regularContent.classList.remove('hidden');
    xlContent.classList.add('hidden');
  } else if (tabName === 'xl') {
    regularContent.classList.add('hidden');
    xlContent.classList.remove('hidden');
  }
  
  // Re-trigger animations for the newly visible content
  setTimeout(function() {
    var visibleContent = tabName === 'regular' ? regularContent : xlContent;
    var animatedElements = visibleContent.querySelectorAll('.mme-animate-on-load');
    animatedElements.forEach(function(element) {
      element.classList.add('mme-visible');
    });
  }, 100);
}

