// Scroll-triggered animations using Intersection Observer
(function(){
  var root = document.getElementById('mme-diatomite');
  if(!root) return;
  
  // Create intersection observer for scroll-triggered animations
  var observer = new IntersectionObserver(function(entries) {
    entries.forEach(function(entry) {
      if (entry.isIntersecting) {
        var element = entry.target;
        var delay = 0;
        
        // Check for custom delay attribute
        var customDelay = element.getAttribute('data-delay');
        if (customDelay) {
          delay = parseInt(customDelay);
        }
        
        // Trigger animation after delay
        setTimeout(function() {
          element.classList.add('mme-visible');
        }, delay);
        
        // Stop observing this element once it's animated
        observer.unobserve(element);
      }
    });
  }, {
    threshold: 0.1, // Trigger when 10% of element is visible
    rootMargin: '0px 0px -50px 0px' // Start animation slightly before element fully enters viewport
  });
  
  // Function to initialize scroll animations
  function initScrollAnimations() {
    // Get all elements with animation classes
    var animatedElements = root.querySelectorAll('.mme-animate-on-load, .mme-animate-fade-in, .mme-animate-slide-left, .mme-animate-slide-right, .mme-animate-scale-in');
    
    // Start observing each element
    animatedElements.forEach(function(element) {
      observer.observe(element);
    });
  }
  
  // Initialize animations when page loads
  if (document.readyState === 'loading') {
    document.addEventListener('DOMContentLoaded', initScrollAnimations);
  } else {
    initScrollAnimations();
  }
})();

// Enhanced FAQ interactions
(function(){
  var root = document.getElementById('mme-diatomite');
  if(!root) return;
  
  // Get all FAQ details elements
  var faqItems = root.querySelectorAll('details');
  
  faqItems.forEach(function(details) {
    var summary = details.querySelector('summary');
    var content = details.querySelector('.mme-faqc');
    
    if (!summary || !content) return;
    
    // Handle click events for smooth animations
    summary.addEventListener('click', function(e) {
      // Prevent default behavior temporarily to control animation timing
      e.preventDefault();
      
      var isOpening = !details.hasAttribute('open');
      
      if (isOpening) {
        // Opening: set open attribute and animate in
        details.setAttribute('open', '');
        
        // Small delay to ensure the open state is processed
        setTimeout(function() {
          content.style.maxHeight = content.scrollHeight + 'px';
        }, 10);
      } else {
        // Closing: animate out then remove open attribute
        content.style.maxHeight = '0px';
        
        setTimeout(function() {
          details.removeAttribute('open');
        }, 400); // Match CSS transition duration
      }
    });
    
    // Handle keyboard accessibility
    summary.addEventListener('keydown', function(e) {
      if (e.key === 'Enter' || e.key === ' ') {
        e.preventDefault();
        summary.click();
      }
    });
  });
})();

// Carousel functionality
(function(){
  var root = document.getElementById('mme-diatomite');
  if(!root) return;
  
  // Initialize all carousels
  function initCarousels() {
    var carousels = root.querySelectorAll('.mme-carousel');
    
    carousels.forEach(function(carousel) {
      var container = carousel.querySelector('.mme-carousel-container');
      var indicators = carousel.querySelectorAll('.mme-carousel-indicator');
      var slides = carousel.querySelectorAll('.mme-carousel-slide');
      var currentSlide = 0;
      var slideInterval;
      
      if (!container || !indicators.length || !slides.length) return;
      
      // Function to go to specific slide
      function goToSlide(slideIndex) {
        currentSlide = slideIndex;
        container.style.transform = 'translateX(-' + (currentSlide * 100) + '%)';
        
        // Update indicators
        indicators.forEach(function(indicator, index) {
          indicator.classList.toggle('active', index === currentSlide);
        });
      }
      
      // Function to go to next slide
      function nextSlide() {
        var nextIndex = (currentSlide + 1) % slides.length;
        goToSlide(nextIndex);
      }
      
      // Auto-advance carousel every 4 seconds
      function startAutoSlide() {
        slideInterval = setInterval(nextSlide, 4000);
      }
      
      // Stop auto-advance
      function stopAutoSlide() {
        if (slideInterval) {
          clearInterval(slideInterval);
          slideInterval = null;
        }
      }
      
      // Add click handlers to indicators
      indicators.forEach(function(indicator, index) {
        indicator.addEventListener('click', function() {
          goToSlide(index);
          stopAutoSlide();
          startAutoSlide(); // Restart auto-slide after manual interaction
        });
      });
      
      // Pause auto-slide on hover
      carousel.addEventListener('mouseenter', stopAutoSlide);
      carousel.addEventListener('mouseleave', startAutoSlide);
      
      // Start auto-slide
      startAutoSlide();
    });
  }
  
  // Initialize carousels when page loads
  if (document.readyState === 'loading') {
    document.addEventListener('DOMContentLoaded', initCarousels);
  } else {
    initCarousels();
  }
})();
